def simulate_nestling_growth():
    # Simulate the growth timeline of a nestling until independence
    days_to_independence = 40
    print(f"Crescent honeyeater nestling becomes independent in {days_to_independence} days.")
    print("Timeline:")
    for day in range(1, days_to_independence + 1):
        if day <= 10:
            stage = "Hatching and early development"
        elif day <= 20:
            stage = "Feather growth and increased activity"
        elif day <= 30:
            stage = "Fledgling stage, learning to fly"
        else:
            stage = "Final growth and preparation for independence"
        print(f"Day {day}: {stage}")

simulate_nestling_growth()
